%[text] # Threshold VAR
%[text] Tutorial file for showcasing  BVARs with threshold based regime switching
%[text:tableOfContents]{"heading":"**Table of Contents**"}
%%
%[text] ## Housekeeping
clear
close all
 
import threshold.*
%%
%[text] ## Convenience functions
%[text] The `extremesFunc` function compresses any number of samples (draws from the posterior) into two numbers - the minimum and the maximum.
percentiles = [10, 50, 90];

prctileFunc = @(x) prctile(x, percentiles, 2);

extremesFunc = @(x) [min(x, [], 2), max(x, [], 2)];

medianFunc = @(x) median(x, 2);

flatFunc = @(x) x(:, :);

defaultColors = get(0, "defaultAxesColorOrder");

%%
%[text] ## Number of Samples
numPresampled = 100;
%%
%[text] ## Prepare data and a reduced-form model
%[text] The properties specific to the threshold VARs are as follows:
%[text] **thresholdVarName** – The variable serving as the threshold indicator for regime identification


estimStart = datex.q(1948,2);
estimEnd = datex.q(2016,4);
estimSpan = datex.span(estimStart, estimEnd);

meta = Meta( ...
    endogenousNames=["dl_y", "dl_cpi", "ir_tb", "stock_index"], ...
    thresholdName="stock_index", ...
    exogenousNames=[], ...
    order=4, ...
    intercept=true, ...
    estimationSpan=estimSpan, ...
    identificationHorizon=20 ...
);
%%
%[text] ## Specifying and loading input data
inputTbx = tablex.fromFile("data/thresholdData.csv");
dataH = DataHolder(meta, inputTbx);
%%
%[text] ## Reduced form model
%[text] 
%[text] ### Minnesota dummies
%[text] please note that this model is using Minnesota dummies for the priors
minnesotaD = dummies.Minnesota();
minnesotaD %[output:856849e3]

%[text] The estimator/model specific settings are the followings
%[text] **VarThreshold** – the prior variance of the threshold
%[text] **MaxDelay** – the maxium delay allowed for the threshold variable for regime identification
%[text] **ThresholdPropStd** – proposal standard deviation of the MH algorithm of the threshold draws
%[text] 
estimatorR = estimator.Threshold(meta);

modelR1 = ReducedForm( ...
    meta=meta ...
    , dataHolder=dataH ...
    , estimator=estimatorR ...
    , dummies={minnesotaD} ...
);

%%
%[text] ## Estimation/sampling of the reduced form model 

modelR1.Estimator.Settings %[output:1f8b7975]
rng(0)
modelR1.initialize();
info5 = modelR1.presample(numPresampled); %[output:1c1dbb76]


thresholds = cellfun(@(x) x.threshold, modelR1.Presampled);

disp("Mean threshold across all samples") %[output:2ddf8f66]
mean(thresholds) %[output:2ae1ca53]

%%
%[text] ## Running Unconditional forecast 
%[text] ### Setting up the forecast range and run the forecast
fcastStart1 = datex.shift(modelR1.Meta.EstimationEnd, -230);
fcastEnd1 = datex.shift(modelR1.Meta.EstimationEnd, -180);
fcastSpan1 = datex.span(fcastStart1, fcastEnd1);

fcastTbx1 = modelR1.forecast(fcastSpan1, IncludeInitial=true);
fcastTbx1 = tablex.apply(fcastTbx1, prctileFunc); 
fcastPrctileTbx1 = tablex.flatten(fcastTbx1);

fcastStart2 = datex.shift(modelR1.Meta.EstimationEnd, -135);
fcastEnd2 = datex.shift(modelR1.Meta.EstimationEnd, -85);
fcastSpan2 = datex.span(fcastStart2, fcastEnd2);

fcastTbx2 = modelR1.forecast(fcastSpan2, IncludeInitial=true);
fcastTbx2 = tablex.apply(fcastTbx2, prctileFunc); 
fcastPrctileTbx2 = tablex.flatten(fcastTbx2);

%[text] ### Visualize the unconditional forecast

chartpack.forecastPercentiles( ... %[output:group:16548d8a] %[output:215bb9f1] %[output:768a372b] %[output:0312ac03]
    fcastPrctileTbx1, modelR1, FigureTitle ="Unconditional forecast from 1st regime") %[output:group:16548d8a] %[output:215bb9f1] %[output:768a372b] %[output:0312ac03]


chartpack.forecastPercentiles( ... %[output:group:417f4bb2] %[output:2494804e] %[output:7528a97c]
    fcastPrctileTbx2, modelR1, FigureTitle ="Unconditional forecast from 2nd regime"); %[output:group:417f4bb2] %[output:2494804e] %[output:7528a97c]
 


